public static string Pascalize(this string input)
{
    // Anti-pattern: .Value.ToUpper() per regex match allocates a string per match
    return WordPartsRegex().Replace(input, match =>
        match.Value.Substring(0, 1).ToUpper() + match.Value.Substring(1));
}

arguments.new_str:
    public static string Pascalize(this string input)
    {
        var matches = WordPartsRegex().Matches(input);
        if (matches.Count == 0)
        {
            return input;
        }

        var sb = new StringBuilder(input.Length);
        foreach (Match match in matches)
        {
            var span = match.ValueSpan;
            sb.Append(char.ToUpperInvariant(span[0]));
            if (span.Length > 1)
            {
#if NET6_0_OR_GREATER
                sb.Append(span.Slice(1));
#else
                sb.Append(match.Value, 1, match.Value.Length - 1);
#endif
            }
        }

        return sb.ToString();
    }

