    public static string Camelize(this string input)
    {
        var matches = WordPartsRegex().Matches(input);
        if (matches.Count == 0)
        {
            return input;
        }

        var sb = new StringBuilder(input.Length);
        var first = true;
        foreach (Match match in matches)
        {
            var span = match.ValueSpan;
            sb.Append(first ? char.ToLowerInvariant(span[0]) : char.ToUpperInvariant(span[0]));
            if (span.Length > 1)
            {
#if NET6_0_OR_GREATER
                sb.Append(span.Slice(1));
#else
                sb.Append(match.Value, 1, match.Value.Length - 1);
#endif
            }

            first = false;
        }

        return sb.ToString();
    }

